import pytest

from somewhere import truncate  # adjust import to your project structure


class TestTruncateHappyPath:
    def test_string_shorter_than_max_len_returned_unchanged(self):
        assert truncate("hello", 10) == "hello"

    def test_string_equal_to_max_len_returned_unchanged(self):
        assert truncate("hello", 5) == "hello"

    def test_string_longer_than_max_len_is_truncated_with_default_suffix(self):
        # max_len=8, suffix='...' -> keep first 5 chars + '...'
        assert truncate("hello world", 8) == "hello..."

    def test_truncated_result_length_equals_max_len(self):
        result = truncate("abcdefghijklmnop", 10)
        assert len(result) == 10
        assert result.endswith("...")

    def test_custom_suffix(self):
        # max_len=8, suffix='--' -> keep first 6 chars + '--'
        assert truncate("hello world", 8, suffix="--") == "hello --"

    def test_custom_suffix_longer_than_default(self):
        # max_len=10, suffix=' [more]' (7 chars) -> keep 3 chars + suffix
        assert truncate("abcdefghijklmnop", 10, suffix=" [more]") == "abc [more]"

    def test_empty_suffix(self):
        assert truncate("hello world", 5, suffix="") == "hello"

    def test_unicode_string_truncation(self):
        # length is measured in code points
        result = truncate("héllo wörld", 8)
        assert result == "héllo..."
        assert len(result) == 8


class TestTruncateEdgeCases:
    def test_empty_string(self):
        assert truncate("", 5) == ""

    def test_empty_string_with_zero_max_len(self):
        assert truncate("", 0) == ""

    def test_max_len_equals_suffix_length(self):
        # max_len=3, suffix='...' (3 chars) -> keep 0 chars + '...'
        assert truncate("hello", 3) == "..."

    def test_single_character_string_within_limit(self):
        assert truncate("a", 5) == "a"

    def test_whitespace_string(self):
        assert truncate("     ", 10) == "     "

    def test_string_with_newlines(self):
        assert truncate("hello\nworld\nfoo", 8) == "hello\n..."

    def test_very_large_max_len(self):
        assert truncate("hello", 10**9) == "hello"

    def test_suffix_same_as_input(self):
        # weird but should still work
        result = truncate("abcdefgh", 5, suffix="...")
        assert result == "ab..."


class TestTruncateErrorCases:
    def test_max_len_less_than_suffix_length_produces_negative_slice(self):
        # max_len=2, suffix='...' (len 3) -> s[:-1] + '...'
        # This is arguably a bug, but documents current behavior.
        result = truncate("hello world", 2)
        # s[:2-3] == s[:-1] == "hello worl"
        assert result == "hello worl..."

    def test_zero_max_len_with_default_suffix(self):
        # max_len=0, suffix='...' -> s[:-3] + '...'
        result = truncate("hello", 0)
        assert result == "he..."

    def test_negative_max_len(self):
        # documents current (surprising) behavior
        result = truncate("hello world", -1)
        assert result == "hello wor..."

    def test_non_string_input_raises_type_error(self):
        with pytest.raises(TypeError):
            truncate(12345, 3)

    def test_non_string_suffix_raises_type_error(self):
        with pytest.raises(TypeError):
            truncate("hello world", 5, suffix=123)

    def test_non_integer_max_len_raises_type_error(self):
        with pytest.raises(TypeError):
            truncate("hello", "5")

    def test_none_input_raises_type_error(self):
        with pytest.raises(TypeError):
            truncate(None, 5)


@pytest.mark.parametrize(
    "s, max_len, suffix, expected",
    [
        ("hello", 10, "...", "hello"),
        ("hello", 5, "...", "hello"),
        ("hello world", 8, "...", "hello..."),
        ("hello world", 5, "", "hello"),
        ("abcdefg", 6, "..", "abcd.."),
        ("", 0, "...", ""),
        ("a", 1, "...", "a"),
    ],
)
def test_truncate_parametrized(s, max_len, suffix, expected):
    assert truncate(s, max_len, suffix=suffix) == expected
